  why_it_matters = '{"hook":"Your website is often the first place customers judge whether to trust, engage, or leave.","problemParagraph":"Many organisations plan web changes without aligned journeys, experience standards, or specifications implementation teams can build against. This design engagement turns web goals into user-centred designs and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined journey direction","description":"Priority web journeys are unclear, making it hard to align teams and stakeholders."},{"title":"Inconsistent experience standards","description":"Brand, UX, and technical patterns are applied unevenly across pages and flows."},{"title":"Build ambiguity","description":"Delivery teams lack the specifications needed to implement with confidence."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"User-centred web designs","description":"Experiences are designed around real user needs with clear journey definitions."},{"title":"Brand-aligned patterns","description":"Visual systems and interaction standards reflect your brand with consistency."},{"title":"Implementation-ready specs","description":"Build teams receive clear specifications that reduce rework and accelerate delivery."}]}}'::jsonb,
