  deliverables_summary = '["This engagement produces design artefacts that translate enterprise data platform requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Workshop-led discovery","Implementation-ready specifications","Governance-aligned delivery"]'::jsonb,
  why_it_matters = '{"hook":"Your data platform is the foundation for reporting, analytics, automation, and every AI initiative you pursue.","problemParagraph":"Many organisations plan data platforms without aligned architecture, governance models, or specifications engineering teams can build against. This design engagement defines data platform blueprints and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined platform architecture","description":"Ingestion, storage, and consumption patterns are not designed coherently."},{"title":"Governance design gaps","description":"Catalogues, lineage, and access models lack operational detail."},{"title":"Build ambiguity","description":"Engineering teams lack specs for pipelines, APIs, and platform services."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned platform designs","description":"Architecture reflects analytics, AI, and operational data needs."},{"title":"Governance standards","description":"Ownership, quality, and access rules are defined upfront."},{"title":"Implementation-ready specs","description":"Engineering receives artefacts that accelerate platform delivery."}]}}'::jsonb,
  faq_intro = 'Key questions about the Enterprise data platform design service.'
WHERE variant_id = 104;

