  deliverables_summary = '["This engagement reviews it operations & support across customer experience and digital engagement.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed discovery scope","Executive-ready findings","No obligation to proceed"]'::jsonb,
  why_it_matters = '{"hook":"IT operations keep critical platforms available, secure, and fit for evolving business needs.","problemParagraph":"Many organisations run IT operations reactively, with unclear service catalogues, inconsistent incident practices, and limited capacity planning. This assessment maps operations maturity and returns prioritised improvements your IT leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive incident handling","description":"Outages are managed ad hoc without consistent runbooks and communication."},{"title":"Opaque service catalogue","description":"Business teams do not know what IT provides or how to request it."},{"title":"Capacity blind spots","description":"Infrastructure and support load are not forecast against business demand."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Operations priority map","description":"You know which services, processes, and tools to improve first."},{"title":"Ranked improvement backlog","description":"Gaps are ordered for design, automation, and investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support IT service transformation funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the It operations & support advisory service.'
WHERE variant_id = 133;

