  overview_paragraphs = '["The Farming operations Advisory service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps operational maturity and returns prioritised improvements your operations leaders can act on.","See how farming operations perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for agribusiness & farm operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews farming operations across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed discovery scope","Executive-ready findings","No obligation to proceed"]'::jsonb,
  why_it_matters = '{"hook":"Farming operations depend on timely data, coordinated field activity, and resilient supply chain execution.","problemParagraph":"Many agribusinesses run farming operations with manual field coordination, inconsistent yield data, and limited visibility into supply chain risk. This assessment maps operational maturity and returns prioritised improvements your operations leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Fragmented operations data","description":"Agricultural operations teams work from disconnected systems without a single operational view."},{"title":"Inconsistent field processes","description":"Standard operating procedures vary by site, team, or shift."},{"title":"Limited digitisation baseline","description":"Automation and analytics opportunities are unclear and unprioritised."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Operational priority map","description":"You know which agricultural operations processes and systems to improve first."},{"title":"Ranked improvement backlog","description":"Gaps are ordered for design, technology, and investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and transformation funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the Farming operations advisory service.'
WHERE variant_id = 149;

